        <div className="hidden md:flex items-center space-x-8 text-sm font-bold uppercase tracking-widest text-white/70">
          <a href="#about" className="hover:text-purple-400 transition-colors">About</a>
          <a href="#gallery" className="hover:text-purple-400 transition-colors">Gallery</a>
          <a href="#roadmap" className="hover:text-purple-400 transition-colors">Roadmap</a>
