import React, { useState } from 'react';
import { generateWaveLore } from '../services/geminiService';

const LoreGenerator: React.FC = () => {
  const [vibe, setVibe] = useState('');
  const [lore, setLore] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!vibe.trim()) return;
    setLoading(true);
    const result = await generateWaveLore(vibe);
    setLore(result);
    setLoading(false);
  };

  return (
    <section id="lore" className="py-24 bg-gradient-to-b from-black to-[#0a0a0a]">
      <div className="container mx-auto px-6">
        <div className="max-w-4xl mx-auto bg-gradient-to-tr from-purple-900/40 to-cyan-900/40 p-1 rounded-[40px] shadow-2xl">
          <div className="bg-black/90 rounded-[38px] p-8 md:p-16 relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-purple-500/10 blur-[80px] -z-10"></div>

            <h2 className="text-3xl md:text-5xl font-black italic uppercase tracking-tighter mb-8 text-center bg-clip-text text-transparent bg-gradient-to-r from-purple-400 to-cyan-400">
              AI Lore Engine
            </h2>

            <p className="text-white/50 text-center mb-12 max-w-lg mx-auto">
              Give your NFT its own soul. Enter a vibe (e.g., "cyberpunk neon storm") and our Gemini-powered engine will manifest its unique wavvvy history.
            </p>

            <div className="flex flex-col md:flex-row gap-4 mb-8">
              <input 
                type="text" 
                value={vibe}
                onChange={(e) => setVibe(e.target.value)}
                placeholder="Enter your vibe..."
                className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-6 py-4 focus:outline-none focus:border-purple-500 transition-all text-white"
              />
              <button 
                onClick={handleGenerate}
                disabled={loading}
                className="px-10 py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-2xl hover:bg-purple-500 hover:text-white transition-all active:scale-95 disabled:opacity-50"
              >
                {loading ? 'Manifesting...' : 'Generate Lore'}
              </button>
            </div>

            {lore && (
              <div className="p-8 bg-purple-500/5 border border-purple-500/20 rounded-3xl animate-fade-in">
                <div className="text-[10px] font-black uppercase text-purple-400 tracking-[0.3em] mb-4">Transmission Received</div>
                <p className="text-xl md:text-2xl font-light italic text-white/90 leading-relaxed font-serif">
                  "{lore}"
                </p>
                <div className="mt-6 flex justify-end">
                   <button className="text-[10px] font-black uppercase tracking-widest opacity-40 hover:opacity-100 transition-opacity">Copy Metadata</button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default LoreGenerator;

